import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { TeamService } from '../../../../core/services/team.service';
import { TeamDTO } from '../../../../core/models/team.model';

@Component({
  selector: 'app-team-details',
  templateUrl: './team-details.component.html',
  styleUrls: ['./team-details.component.scss']
})
export class TeamDetailsComponent implements OnInit {
  team: TeamDTO | null = null;
  isLoading = true;
  errorMessage = '';
  teamId: string = '';

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private teamService: TeamService
  ) {}

  ngOnInit(): void {
    this.teamId = this.route.snapshot.paramMap.get('teamId') || '';
    if (this.teamId) {
      this.loadTeamDetails();
    } else {
      this.errorMessage = 'Team ID not provided';
      this.isLoading = false;
    }
  }

  loadTeamDetails(): void {
    this.isLoading = true;
    this.errorMessage = '';

    this.teamService.getTeamDetails(this.teamId).subscribe({
      next: (team) => {
        this.team = team;
        this.isLoading = false;
        console.log('TeamDetailsComponent - Team loaded:', team);
      },
      error: (error) => {
        console.error('TeamDetailsComponent - Error loading team:', error);
        this.errorMessage = 'Failed to load team details. Please try again.';
        this.isLoading = false;
      }
    });
  }

  goBack(): void {
    this.router.navigate(['/teams']);
  }

  editTeam(): void {
    this.router.navigate(['/teams', this.teamId, 'manage']);
  }
}
<div class="team-details-container">
  <!-- Loading State -->
  <div class="loading-state" *ngIf="isLoading">
    <div class="loading-spinner">
      <div class="spinner"></div>
      <p>Loading team details...</p>
    </div>
  </div>

  <!-- Error State -->
  <div class="error-state" *ngIf="errorMessage">
    <div class="error-card">
      <div class="error-icon">⚠️</div>
      <h3>Oops! Something went wrong</h3>
      <p>{{ errorMessage }}</p>
      <button class="btn-secondary" (click)="loadTeamDetails()">Try Again</button>
      <button class="btn-primary" (click)="goBack()">Go Back</button>
    </div>
  </div>

  <!-- Team Details -->
  <div class="team-details" *ngIf="!isLoading && !errorMessage && team">
    <div class="page-header">
      <button class="btn-secondary back-button" (click)="goBack()">
        <span>←</span>
        <span>Back to Teams</span>
      </button>
      <h1 class="page-title">{{ team.nome || team.leaderNome || 'Team Details' }}</h1>
      <button class="btn-primary" (click)="editTeam()">
        <span>⚙️</span>
        <span>Manage Team</span>
      </button>
    </div>

    <div class="team-info-card">
      <div class="team-header">
        <div class="team-name">
          <h2>{{ team.nome || 'Unknown Team' }}</h2>
          <p class="team-description" *ngIf="team.descrizione">{{ team.descrizione }}</p>
          <p class="team-description" *ngIf="!team.descrizione">No description available</p>
        </div>
        <div class="team-stats">
          <div class="stat-item">
            <span class="stat-label">Members</span>
            <span class="stat-value">{{ team.membriIds?.length || 0 }}</span>
          </div>
          <div class="stat-item">
            <span class="stat-label">Created</span>
            <span class="stat-value">{{ team.dataCreazione ? (team.dataCreazione | date:'short') : 'Unknown' }}</span>
          </div>
        </div>
      </div>

      <div class="team-leader">
        <h3>Team Leader</h3>
        <div class="leader-info">
          <div class="leader-avatar">👑</div>
          <div class="leader-details">
            <span class="leader-name">{{ team.leaderNome || 'Unknown Leader' }}</span>
            <span class="leader-role">Team Leader</span>
          </div>
        </div>
      </div>

      <div class="team-members" *ngIf="team.membriNomi && team.membriNomi.length > 0">
        <h3>Team Members ({{ team.membriNomi.length }})</h3>
        <div class="members-grid">
          <div class="member-card" *ngFor="let memberName of team.membriNomi; let i = index">
            <div class="member-avatar">
              {{ memberName.charAt(0).toUpperCase() }}
            </div>
            <div class="member-info">
              <span class="member-name">{{ memberName }}</span>
              <span class="member-role" *ngIf="team.membriIds && team.leaderId && team.membriIds[i] === team.leaderId">👑 Leader</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
